// Extrae y formatea los datos relevantes del pliego
// para pasarlos al motor de ingeniería técnica

return items.map((item) => {
  const j = item.json || {};

  // El input puede venir directamente del workflow de pliegos.
  // Los datos reales pueden estar en j.output o directamente en j.
  const pliego = j.output ?? j;

  const equipamiento = (pliego.equipamiento_requerido || [])
    .map(cat => {
      const itemsList = (cat.items || []).join(', ');
      return `CATEGORÍA: ${cat.categoria}\nItems: ${itemsList}\nCantidad: ${cat.cantidad_aprox ?? 'No especificada'}\nNotas: ${cat.notas ?? 'Ninguna'}`;
    })
    .join('\n\n');

  const protocolos = (pliego.integraciones_y_protocolos || []).join(', ') || 'No especificados';
  const alcance = pliego.alcance_tecnico || {};
  const sistemas = (alcance.sistemas || []).join(', ') || 'No especificados';
  const tareas = (alcance.tareas_principales || []).join(', ') || 'No especificadas';
  const riesgos = (pliego.riesgos_y_ambiguedades || []).join('; ') || 'Ninguno identificado';

  const contexto = `TIPO DE PROYECTO: ${pliego.tipo_proyecto ?? 'N/D'}
CLIENTE: ${pliego.cliente ?? 'N/D'}
DESCRIPCIÓN TÉCNICA: ${alcance.descripcion ?? pliego.resumen_ejecutivo ?? 'N/D'}

SISTEMAS A INSTALAR: ${sistemas}
TAREAS PRINCIPALES: ${tareas}
PROTOCOLOS E INTEGRACIONES: ${protocolos}

EQUIPAMIENTO REQUERIDO:
${equipamiento || 'No especificado'}

COMPLEJIDAD ESTIMADA: ${pliego.clasificacion?.complejidad ?? 'N/D'}
PRESUPUESTO: ${pliego.presupuesto?.importe ?? 'N/D'} ${pliego.presupuesto?.moneda ?? ''}
RIESGOS IDENTIFICADOS: ${riesgos}`;

  return {
    json: {
      ...j,
      _contexto_ingenieria: contexto,
      _pliego_data: pliego,
    },
  };
});

// Ensambla la respuesta JSON estructurada final con metadatos
// Soporta tanto output de Information Extractor (objeto) como de Agent (string JSON)

return items.map((item) => {
  const j = item.json || {};

  // El output puede ser un objeto (Information Extractor) o un string JSON (Agent)
  let ing = j.output || {};
  if (typeof ing === 'string') {
    try {
      // Limpiar posibles bloques de código markdown
      const cleaned = ing.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
      ing = JSON.parse(cleaned);
    } catch(e) {
      // Si no se puede parsear, envolver el texto en un objeto mínimo
      ing = { resumen_tecnico: ing, error_parseo: true };
    }
  }

  const pliego = j._pliego_data || {};

  const now = new Date().toISOString();
  const engineering_id = `ING-${now.replace(/[-:TZ.]/g, '').slice(0, 14)}`;

  const horas = ing.horas_estimadas_totales || {};
  const configs = ing.configuraciones_requeridas || {};

  const flagControl = configs.programacion_control?.requerida === true;
  const flagDSP = configs.dsp_audio?.requerida === true;
  const flagIT = configs.integracion_red_it?.requerida === true;
  const flagCalib = configs.calibracion_puesta_marcha?.requerida === true;

  const resumenFlags = [
    flagControl ? 'Programación de control' : null,
    flagDSP ? 'Config. DSP/Audio' : null,
    flagIT ? 'Integración IT/Red' : null,
    flagCalib ? 'Calibración y puesta en marcha' : null,
  ].filter(Boolean).join(' | ') || 'Sin configuraciones especiales';

  return {
    json: {
      engineering_id,
      generado_en: now,
      pliego_id: j.project_id || null,
      cliente: pliego.cliente || null,
      tipo_proyecto: pliego.tipo_proyecto || null,
      complejidad: ing.complejidad_integracion || null,
      horas_totales: horas.total || null,
      flags_configuracion: resumenFlags,
      ingenieria_tecnica: ing,
      _pliego_data: pliego,
    },
  };
});

// Genera un informe HTML legible para el equipo de ingeniería
// Incluye columna de referencia de catálogo para productos reales

return items.map((item) => {
  const j = item.json || {};
  const ing = j.ingenieria_tecnica || {};
  const configs = ing.configuraciones_requeridas || {};
  const horas = ing.horas_estimadas_totales || {};

  const col = (val) => val === true ? '✅' : '❌';

  // ── Productos recomendados ──────────────────────────────────────────────
  const productosHtml = (ing.productos_recomendados || []).map(cat => {
    const opcionesHtml = (cat.opciones || []).map((op, i) => `
      <tr class="${i === 0 ? 'opcion-principal' : 'opcion-alt'}">
        <td>${i === 0 ? '⭐ Principal' : 'Alternativa'}</td>
        <td><strong>${op.fabricante ?? ''}</strong></td>
        <td>${op.modelo ?? ''}</td>
        <td>${op.referencia_catalogo ? `📋 ${op.referencia_catalogo}` : '<span class="grey">—</span>'}</td>
        <td>${(op.caracteristicas || []).join(', ')}</td>
        <td>${op.justificacion ?? ''}</td>
      </tr>`).join('');
    return `
    <div class="categoria">
      <h3>📦 ${cat.categoria} <span class="badge">${cat.cantidad ?? ''} ud.</span></h3>
      <p class="necesidad">${cat.necesidad ?? ''}</p>
      <table>
        <thead><tr><th>Tipo</th><th>Fabricante</th><th>Modelo</th><th>Ref. Catálogo</th><th>Características</th><th>Justificación</th></tr></thead>
        <tbody>${opcionesHtml}</tbody>
      </table>
      ${cat.notas_tecnicas ? `<p class="nota">📝 ${cat.notas_tecnicas}</p>` : ''}
    </div>`;
  }).join('');

  // ── Configuraciones requeridas ─────────────────────────────────────────
  const configItems = [
    { key: 'programacion_control',   label: 'Programación de control', icon: '⚙️' },
    { key: 'dsp_audio',              label: 'DSP / Audio',             icon: '🎛️' },
    { key: 'integracion_red_it',     label: 'Integración IT / Red',    icon: '🌐' },
    { key: 'calibracion_puesta_marcha', label: 'Calibración y puesta en marcha', icon: '🔧' },
  ];
  const configsHtml = configItems.map(({ key, label, icon }) => {
    const c = configs[key] || {};
    const req = c.requerida;
    return `
    <div class="config-card ${req ? 'required' : 'not-required'}">
      <h4>${icon} ${label} ${col(req)}</h4>
      ${req ? `
        <p>${c.descripcion ?? ''}</p>
        ${c.plataforma_recomendada ? `<p><strong>Plataforma:</strong> ${c.plataforma_recomendada}</p>` : ''}
        ${c.horas_estimadas ? `<p><strong>Horas estimadas:</strong> ${c.horas_estimadas}h | <strong>Complejidad:</strong> ${c.complejidad ?? 'N/D'}</p>` : ''}
        ${c.dias_estimados ? `<p><strong>Días estimados:</strong> ${c.dias_estimados} días</p>` : ''}
        ${(c.requisitos_red || []).length > 0 ? `<ul>${c.requisitos_red.map(r => `<li>${r}</li>`).join('')}</ul>` : ''}
        ${c.coordinacion_it_necesaria ? `<p>⚠️ Requiere coordinación con departamento IT del cliente</p>` : ''}
      ` : '<p class="grey">No requerido para este proyecto</p>'}
    </div>`;
  }).join('');

  const html = `<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="UTF-8">
  <title>Informe Ingeniería - ${j.engineering_id}</title>
  <style>
    body { font-family: Arial, sans-serif; max-width: 1100px; margin: 0 auto; padding: 24px; color: #222; }
    h1 { color: #1a3c6e; border-bottom: 3px solid #1a3c6e; padding-bottom: 8px; }
    h2 { color: #2c5f9e; margin-top: 32px; }
    h3 { color: #444; }
    .meta { background: #f5f7fa; border-radius: 8px; padding: 16px; margin-bottom: 24px; display: grid; grid-template-columns: repeat(3, 1fr); gap: 12px; }
    .meta-item { display: flex; flex-direction: column; }
    .meta-label { font-size: 11px; text-transform: uppercase; color: #888; }
    .meta-value { font-weight: bold; font-size: 15px; }
    .categoria { background: #fff; border: 1px solid #dde3ec; border-radius: 8px; padding: 20px; margin-bottom: 20px; }
    table { width: 100%; border-collapse: collapse; margin-top: 12px; font-size: 13px; }
    th { background: #1a3c6e; color: white; padding: 8px 12px; text-align: left; }
    td { padding: 8px 12px; border-bottom: 1px solid #eee; }
    .opcion-principal td { background: #f0f4ff; }
    .badge { background: #1a3c6e; color: white; border-radius: 12px; padding: 2px 10px; font-size: 12px; margin-left: 8px; }
    .necesidad { color: #555; font-style: italic; margin: 4px 0 12px; }
    .nota { background: #fffbe6; border-left: 3px solid #f0c000; padding: 8px 12px; border-radius: 0 4px 4px 0; font-size: 13px; }
    .config-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 16px; }
    .config-card { border-radius: 8px; padding: 16px; border: 1px solid #dde3ec; }
    .config-card.required { border-color: #2c5f9e; background: #f7faff; }
    .config-card.not-required { opacity: 0.5; }
    .config-card h4 { margin: 0 0 10px; font-size: 15px; }
    .grey { color: #999; font-style: italic; }
    .horas-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 12px; margin: 16px 0; }
    .hora-card { background: #f0f4ff; border-radius: 8px; padding: 14px; text-align: center; }
    .hora-num { font-size: 28px; font-weight: bold; color: #1a3c6e; }
    .hora-label { font-size: 11px; color: #666; text-transform: uppercase; margin-top: 4px; }
    .hora-total { background: #1a3c6e; color: white; border-radius: 8px; padding: 14px; text-align: center; }
    .advertencias { background: #fff8e1; border-left: 4px solid #f9a825; border-radius: 0 8px 8px 0; padding: 16px; }
    .preguntas { background: #e8f5e9; border-left: 4px solid #43a047; border-radius: 0 8px 8px 0; padding: 16px; }
    ul { padding-left: 20px; margin: 8px 0; }
    li { margin: 4px 0; }
    .resumen-box { background: #1a3c6e; color: white; border-radius: 8px; padding: 20px; margin-bottom: 24px; }
    .catalogo-badge { background: #43a047; color: white; border-radius: 4px; padding: 1px 6px; font-size: 11px; }
    footer { text-align: center; color: #aaa; font-size: 12px; margin-top: 48px; border-top: 1px solid #eee; padding-top: 12px; }
  </style>
</head>
<body>
  <h1>📐 Informe de Ingeniería Técnica AV</h1>

  <div class="meta">
    <div class="meta-item"><span class="meta-label">ID Informe</span><span class="meta-value">${j.engineering_id}</span></div>
    <div class="meta-item"><span class="meta-label">Cliente</span><span class="meta-value">${j.cliente ?? 'N/D'}</span></div>
    <div class="meta-item"><span class="meta-label">Tipo de proyecto</span><span class="meta-value">${j.tipo_proyecto ?? 'N/D'}</span></div>
    <div class="meta-item"><span class="meta-label">Complejidad integración</span><span class="meta-value">${j.complejidad ?? 'N/D'}</span></div>
    <div class="meta-item"><span class="meta-label">Horas totales estimadas</span><span class="meta-value">${j.horas_totales ?? 'N/D'}h</span></div>
    <div class="meta-item"><span class="meta-label">Generado</span><span class="meta-value">${new Date(j.generado_en).toLocaleDateString('es-ES')}</span></div>
  </div>

  <div class="resumen-box">
    <p style="margin:0;font-size:15px;">📋 ${ing.resumen_tecnico ?? 'Sin resumen disponible'}</p>
  </div>

  <h2>🛒 Productos Recomendados</h2>
  ${productosHtml || '<p>No se han identificado categorías de equipamiento.</p>'}

  <h2>⚙️ Configuraciones y Programación Requeridas</h2>
  <div class="config-grid">${configsHtml}</div>

  <h2>⏱️ Estimación de Horas</h2>
  <div class="horas-grid">
    <div class="hora-card"><div class="hora-num">${horas.programacion_control ?? 0}</div><div class="hora-label">Prog. control</div></div>
    <div class="hora-card"><div class="hora-num">${horas.configuracion_dsp ?? 0}</div><div class="hora-label">DSP / Audio</div></div>
    <div class="hora-card"><div class="hora-num">${horas.instalacion ?? 0}</div><div class="hora-label">Instalación</div></div>
    <div class="hora-card"><div class="hora-num">${horas.puesta_marcha ?? 0}</div><div class="hora-label">Puesta en marcha</div></div>
  </div>
  <div class="hora-total" style="text-align:center;border-radius:8px;padding:14px;margin-bottom:8px;">
    <span style="font-size:18px;font-weight:bold;">TOTAL ESTIMADO: ${horas.total ?? 0} horas</span>
  </div>

  ${(ing.servicios_complementarios || []).length > 0 ? `
  <h2>🔩 Servicios Complementarios</h2>
  <ul>${(ing.servicios_complementarios || []).map(s => `<li><strong>${s.servicio}</strong>: ${s.descripcion}</li>`).join('')}</ul>` : ''}

  ${(ing.advertencias_tecnicas || []).length > 0 ? `
  <h2>⚠️ Advertencias Técnicas</h2>
  <div class="advertencias"><ul>${(ing.advertencias_tecnicas || []).map(a => `<li>${a}</li>`).join('')}</ul></div>` : ''}

  ${(ing.preguntas_a_resolver || []).length > 0 ? `
  <h2>❓ Preguntas a Resolver Antes de Ofertar</h2>
  <div class="preguntas"><ul>${(ing.preguntas_a_resolver || []).map(p => `<li>${p}</li>`).join('')}</ul></div>` : ''}

  <footer>Generado automáticamente · ${j.engineering_id} · ${j.generado_en}</footer>
</body>
</html>`;

  // Devuelve el JSON completo sin los campos internos
  const { _pliego_data, _contexto_ingenieria, output, ...limpio } = j;
  return {
    json: {
      ...limpio,
      informe_html: html,
    },
  };
});
